"""Device detection and validation utilities."""

import torch
import click
from .types import DeviceType


def detect_device(device_preference: str = DeviceType.AUTO.value) -> str:
    """
    Detect the best available device.

    Args:
        device_preference: User's device preference

    Returns:
        Detected device string

    Raises:
        click.ClickException: If specified device is not available
    """
    if device_preference == DeviceType.AUTO.value:
        # Auto-detect best available device
        if torch.cuda.is_available():
            return "cuda:0"
        elif torch.backends.mps.is_available():
            return "mps" 
        else:
            return "cpu"

    # Validate specific device request
    device = validate_device(device_preference)
    return device


def validate_device(device: str) -> str:
    """
    Validate that a specific device is available.

    Args:
        device: Device string to validate

    Returns:
        Validated device string

    Raises:
        click.ClickException: If device is not available
    """
    device = device.lower()

    # Handle common device formats
    if device == "cpu":
        return "cpu"

    if device.startswith("cuda"):
        if not torch.cuda.is_available():
            raise click.ClickException(
                "CUDA is not available on this system. Use --device cpu or --device mps."
            )

        # Validate specific CUDA device if specified
        if ":" in device:
            try:
                device_id = int(device.split(":")[1])
                if device_id >= torch.cuda.device_count():
                    raise click.ClickException(
                        f"CUDA device {device_id} not available. "
                        f"Available devices: 0-{torch.cuda.device_count()-1}"
                    )
            except ValueError:
                raise click.ClickException(f"Invalid CUDA device format: {device}")

        return device

    if device == "mps":
        if not torch.backends.mps.is_available():
            raise click.ClickException(
                "MPS is not available on this system. Use --device cpu or --device cuda."
            )
        return "mps"

    # For any other device string, try to create a torch device to validate
    try:
        torch.device(device)
        return device
    except Exception:
        raise click.ClickException(
            f"Invalid device: {device}. Use cpu, cuda, cuda:N, mps, or auto."
        )

